import{_ as t,o,c as i,a2 as a}from"./chunks/framework.CKCxdkvf.js";const p=JSON.parse('{"title":"ADR-030 — /fly trajectory math: pure-function isolation + per-mission validation","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-030.md","filePath":"adr/ADR-030.md"}'),s={name:"adr/ADR-030.md"};function n(r,e,d,l,c,h){return o(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="adr-030-—-fly-trajectory-math-pure-function-isolation-per-mission-validation" tabindex="-1">ADR-030 — /fly trajectory math: pure-function isolation + per-mission validation <a class="header-anchor" href="#adr-030-—-fly-trajectory-math-pure-function-isolation-per-mission-validation" aria-label="Permalink to &quot;ADR-030 — /fly trajectory math: pure-function isolation + per-mission validation&quot;">​</a></h1><blockquote><p>Status · Accepted Date · 2026-05-02 Closes · Phase 4 of the multi-phase polish plan TA anchor · §components/fly-screen · §components/test-infra Related ADRs · ADR-009 (free-return scenario), ADR-010 (Keplerian half-ellipses), ADR-015 (Vitest+Playwright), ADR-027 (mission flight params)</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>Through v0.1.x the /fly trajectory math grew incrementally inside <code>src/routes/fly/+page.svelte</code>: vis-viva for heliocentric speed, Euclidean distance helpers, signal-delay light-minute calc, MET derivations, Moon-mode Bezier curves, ∆v ledger arithmetic. All visible to the renderer, all invisible to vitest. Issue #31 added rich golden values (peak heliocentric speed, V∞, total ∆v) for 21 measured missions but nothing in the test suite asserted that the visualization matches those values.</p><p>This ADR locks the pure-function boundary + the per-mission validation harness shape.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><h3 id="pure-function-boundary" tabindex="-1">Pure-function boundary <a class="header-anchor" href="#pure-function-boundary" aria-label="Permalink to &quot;Pure-function boundary&quot;">​</a></h3><p><code>src/lib/fly-physics.ts</code> is the authoritative source for every numeric formula consumed by /fly&#39;s render loop. The <code>+page.svelte</code> file imports + composes; it does not own the math.</p><p>Functions extracted (v0.2.0):</p><table tabindex="0"><thead><tr><th>Function</th><th>Role</th><th>Source formula</th></tr></thead><tbody><tr><td><code>heliocentricSpeed(rAu, aTransferAu)</code></td><td>Vis-viva on transfer ellipse</td><td><code>√(µ·(2/r − 1/a)) × AU/yr→km/s</code></td></tr><tr><td><code>distanceBetween(a, b)</code></td><td>Heliocentric Euclidean distance</td><td><code>hypot(ax−bx, az−bz)</code></td></tr><tr><td><code>auToKm(au)</code> / <code>auToMkm(au)</code></td><td>Unit conversion</td><td><code>au × 149_597_870.7</code></td></tr><tr><td><code>signalDelayMin(distAu)</code></td><td>One-way light-minute delay</td><td><code>(distAu × AU_TO_KM) / c / 60</code></td></tr><tr><td><code>missionElapsedDays(simDay, depDay, arrDay, totalMissionDays)</code></td><td>MET from arc progress</td><td>linear interp + clamp</td></tr><tr><td><code>dvRemaining(total, used)</code></td><td>∆v ledger</td><td><code>max(0, total − used)</code></td></tr><tr><td><code>moonPositionAtMet(metDays)</code></td><td>Moon orbital position in scene coords</td><td><code>(cos θ, sin θ) × MOON_VISUAL_DISTANCE</code></td></tr><tr><td><code>moonOutboundArc(moonPos, steps)</code></td><td>Earth → Moon Bezier</td><td>quadratic Bezier with perpendicular control offset</td></tr><tr><td><code>moonReturnArc(moonPos, steps)</code></td><td>Moon → Earth Bezier</td><td>mirrored Bezier with opposite offset sign</td></tr></tbody></table><p>Constants centralised in <code>src/lib/fly-physics-constants.ts</code>:</p><ul><li><code>MU_SUN_AU3_YR2</code>, <code>AU_TO_KM</code>, <code>AU_TO_LMIN</code>, <code>AU_PER_YR_TO_KMS</code></li><li><code>C_LIGHT_KM_S</code>, <code>MOON_ORBITAL_PERIOD_DAYS</code>, <code>MOON_VISUAL_DISTANCE</code></li><li><code>MOON_BEZIER_CTRL_OFFSET</code></li></ul><h3 id="validation-harness" tabindex="-1">Validation harness <a class="header-anchor" href="#validation-harness" aria-label="Permalink to &quot;Validation harness&quot;">​</a></h3><p><code>src/lib/fly-physics-validation.test.ts</code> walks 10 real missions (9 measured + 1 sparse) and asserts:</p><ol><li>Peak heliocentric speed along the outbound arc matches <code>mission.flight.cruise.peak_heliocentric_speed_km_s</code> within a per-mission tolerance.</li><li>Outbound-arc terminal radius lands within 0.05 AU of the destination orbit.</li></ol><p><strong>Tolerance bands</strong> reflect the Hohmann-approximation envelope of the model — /fly visualises a Hohmann transfer ellipse, not a real Lambert solution. The harness validates that the visualization <em>is close to</em> reality, not exact:</p><table tabindex="0"><thead><tr><th>Class</th><th>Missions</th><th style="text-align:right;">Peak-speed tolerance</th></tr></thead><tbody><tr><td>Energetic (C3 ≳ 10)</td><td>Curiosity, Perseverance, InSight, MAVEN, Mars Express, Hope, Tianwen-1</td><td style="text-align:right;">1.5 km/s</td></tr><tr><td>Direct entry / flyby (high V∞)</td><td>Mariner 4, Mars Pathfinder</td><td style="text-align:right;">2.0 km/s</td></tr><tr><td>Sparse (reconstructed golden)</td><td>Mars 3</td><td style="text-align:right;">3.0 km/s</td></tr></tbody></table><p>The test helper <code>src/lib/test-helpers/expect-close.ts#expectCloseTo()</code> provides explicit ±tolerance assertions with descriptive errors so vitest output makes clear which mission diverged.</p><h3 id="v∞-shaping-coverage" tabindex="-1">V∞ shaping coverage <a class="header-anchor" href="#v∞-shaping-coverage" aria-label="Permalink to &quot;V∞ shaping coverage&quot;">​</a></h3><p>The V∞ shaping inside <code>outboundArc()</code> (<code>src/lib/mission-arc.ts:76</code>) shipped in v0.1.10 with no unit-test coverage. v0.2.0 adds 4 tests in <code>fly-physics.test.ts</code>:</p><ul><li>Baseline passthrough (V∞=undefined matches no-arg call)</li><li>Bend out for energetic V∞</li><li>Hohmann-baseline V∞ produces ~zero bend</li><li>Extreme V∞ clamped to bend cap (no unphysical loop)</li></ul><h3 id="moon-bezier-coverage" tabindex="-1">Moon Bezier coverage <a class="header-anchor" href="#moon-bezier-coverage" aria-label="Permalink to &quot;Moon Bezier coverage&quot;">​</a></h3><p>Pre-v0.2.0 the Moon-mode arcs in <code>+page.svelte:478–512</code> had no test coverage. After extraction to <code>fly-physics.ts#moonOutboundArc/moonReturnArc</code>, 6 tests cover:</p><ul><li>Arc start at Earth (origin), end at Moon position</li><li>Period wrap on <code>moonPositionAtMet()</code></li><li>Outbound + return arcs curve oppositely (control-point flip)</li><li>t=0 sits on the +X axis</li></ul><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p>The decision cluster around three principles:</p><ul><li><strong>CLAUDE.md &quot;every function in <code>src/lib/orbital.ts</code> must have tests&quot;</strong> — extending that to fly-physics.ts is the structural fix for the test gap. The pure-function boundary is what makes the validation possible.</li><li><strong>PA §promises — real physics</strong> — the per-mission validation harness is the structural assertion that the /fly visualization tracks public flight-data records within a documented tolerance envelope.</li><li><strong>PA §promises — fail honestly</strong> — the tolerance bands are wider for higher-energy transfers (and explicitly widest for sparse-data missions) because we&#39;re using a Hohmann approximation. The harness names the limitation in code rather than papering over it.</li></ul><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ul><li><strong>Use real Lambert solver per mission</strong> — the existing <code>src/lib/lambert-grid.ts</code> could in principle be parameterised per mission. Rejected because (a) the v0.1.6 work already pre-computes per-destination grids, not per-mission Lambert, and (b) the educational visualization doesn&#39;t need exact Lambert; a Hohmann-with-V∞-shaping model is honest enough.</li><li><strong>toBeCloseTo decimal-place tolerance</strong> — vitest&#39;s built-in. Rejected because decimal-place tolerance couples too tightly to value magnitude (33.4 vs 33.5 fails at 1 digit, passes at 0). Explicit ±tolerance is more honest.</li><li><strong>Fewer than 10 missions in the harness</strong> — would speed tests but reduce coverage. The 10-mission set is the minimum that exercises the breadth of energy regimes (low V∞ Mars orbiters → high V∞ flyby missions → reconstructed sparse data).</li><li><strong>Validate signal delay + MET separately per mission</strong> — overkill; signal delay is a function of distance only and gets unit-test coverage; MET is a linear interp and gets unit-test coverage. The mission-specific harness focuses on trajectory geometry.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p><strong>Positive:</strong></p><ul><li>/fly math is now testable independently of the Three.js + Canvas2D rendering. Refactors to the geometry don&#39;t risk silent regressions.</li><li>Per-mission tolerance bands documented in code, not folklore. New missions added to the catalogue can be validated by adding a single line to <code>CASES</code>.</li><li>The 4 V∞ shaping tests close the v0.1.10 coverage gap.</li><li><code>expect-close.ts</code> is reusable for any future per-mission validation (e.g. when v0.3.0 adds outer-planet missions).</li></ul><p><strong>Negative:</strong></p><ul><li>One extra import line per consumer in <code>+page.svelte</code> (acceptable cost vs the visibility of the math).</li><li>Tolerance bands are loose (1.5 km/s for energetic transfers) — the harness validates the model envelope, not Lambert-grade precision. This is intentional but worth documenting (done above).</li><li>11 new test entries in the validation harness — adds ~200 ms to the test run. Acceptable.</li></ul><h2 id="implementation-notes" tabindex="-1">Implementation notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation notes&quot;">​</a></h2><ul><li>Phase 4 ships in v0.2.0 (minor version bump because the trajectory core is touched).</li><li>The /fly <code>+page.svelte</code> net diff is ~30 lines smaller after extraction — formulas replaced by import + call sites.</li><li>Moon-mode arc generation in <code>applyMissionAsLoaded</code> now calls <code>flyMoonOutboundArc()</code> + <code>flyMoonReturnArc()</code> instead of inline Bezier loops.</li><li>Validation harness (<code>fly-physics-validation.test.ts</code>) reads mission JSON directly from <code>static/data/missions/&lt;dest&gt;/&lt;id&gt;.json</code> — same path the runtime uses.</li></ul><p>Future work tracked separately:</p><ul><li>Outer-planet missions (Voyager 2, New Horizons, Galileo, Dawn) join the harness in v0.3.0 once their flight data lands.</li><li>Lighthouse CI gate (Theme C.C3 deferred from v0.1.12) — independent of this ADR.</li></ul>',38)])])}const m=t(s,[["render",n]]);export{p as __pageData,m as default};
